import asyncio
import json
import uuid
import websockets
from dataclasses import dataclass, field, asdict
from typing import Optional
from enum import Enum


class ItemRarity(Enum):
    COMMON = "common"
    UNCOMMON = "uncommon"
    RARE = "rare"
    EPIC = "epic"
    LEGENDARY = "legendary"


@dataclass
class Item:
    item_id: str
    name: str
    rarity: str
    value: int
    owner_id: Optional[str] = None

    def to_dict(self):
        return {
            "item_id": self.item_id,
            "name": self.name,
            "rarity": self.rarity,
            "value": self.value,
            "owner_id": self.owner_id,
        }


@dataclass
class Player:
    player_id: str
    name: str
    gold: int = 1000
    inventory: list = field(default_factory=list)

    def to_dict(self):
        return {
            "player_id": self.player_id,
            "name": self.name,
            "gold": self.gold,
            "inventory": [item_id for item_id in self.inventory],
        }


class TradeState(Enum):
    PENDING = "pending"
    ACCEPTED_BY_INITIATOR = "accepted_by_initiator"
    ACCEPTED_BY_RECEIVER = "accepted_by_receiver"
    COMPLETED = "completed"
    CANCELLED = "cancelled"


@dataclass
class TradeOffer:
    trade_id: str
    initiator_id: str
    receiver_id: str
    initiator_items: list = field(default_factory=list)
    receiver_items: list = field(default_factory=list)
    initiator_gold: int = 0
    receiver_gold: int = 0
    initiator_accepted: bool = False
    receiver_accepted: bool = False
    state: TradeState = TradeState.PENDING
    locked: bool = False

    def to_dict(self):
        return {
            "trade_id": self.trade_id,
            "initiator_id": self.initiator_id,
            "receiver_id": self.receiver_id,
            "initiator_items": self.initiator_items,
            "receiver_items": self.receiver_items,
            "initiator_gold": self.initiator_gold,
            "receiver_gold": self.receiver_gold,
            "initiator_accepted": self.initiator_accepted,
            "receiver_accepted": self.receiver_accepted,
            "state": self.state.value,
        }


class GameServer:
    def __init__(self):
        self.players: dict[str, Player] = {}
        self.items: dict[str, Item] = {}
        self.connections: dict[str, websockets.WebSocketServerProtocol] = {}
        self.active_trades: dict[str, TradeOffer] = {}
        # Per-player lock to prevent concurrent modifications to a player's inventory/gold
        self.player_locks: dict[str, asyncio.Lock] = {}
        # Per-item lock to prevent concurrent transfers of the same item
        self.item_locks: dict[str, asyncio.Lock] = {}
        # Global trade lock for trade creation/lookup atomicity
        self.trade_lock = asyncio.Lock()
        # Track which players are currently in a trade to prevent multiple simultaneous trades
        self.players_in_trade: set[str] = {}
        self.players_in_trade = set()

    def _get_player_lock(self, player_id: str) -> asyncio.Lock:
        if player_id not in self.player_locks:
            self.player_locks[player_id] = asyncio.Lock()
        return self.player_locks[player_id]

    def _get_item_lock(self, item_id: str) -> asyncio.Lock:
        if item_id not in self.item_locks:
            self.item_locks[item_id] = asyncio.Lock()
        return self.item_locks[item_id]

    def create_item(self, name: str, rarity: str, value: int, owner_id: Optional[str] = None) -> Item:
        item_id = str(uuid.uuid4())
        item = Item(item_id=item_id, name=name, rarity=rarity, value=value, owner_id=owner_id)
        self.items[item_id] = item
        if owner_id and owner_id in self.players:
            self.players[owner_id].inventory.append(item_id)
        return item

    def create_player(self, name: str) -> Player:
        player_id = str(uuid.uuid4())
        player = Player(player_id=player_id, name=name)
        self.players[player_id] = player
        self.player_locks[player_id] = asyncio.Lock()

        # Give starter items
        starter_items = [
            ("Iron Sword", ItemRarity.COMMON.value, 50),
            ("Wooden Shield", ItemRarity.COMMON.value, 30),
            ("Health Potion", ItemRarity.COMMON.value, 10),
            ("Leather Armor", ItemRarity.UNCOMMON.value, 100),
            ("Magic Ring", ItemRarity.RARE.value, 500),
        ]
        for item_name, rarity, value in starter_items:
            self.create_item(item_name, rarity, value, player_id)

        return player

    async def send_to_player(self, player_id: str, message: dict):
        if player_id in self.connections:
            try:
                await self.connections[player_id].send(json.dumps(message))
            except websockets.exceptions.ConnectionClosed:
                pass

    async def broadcast(self, message: dict, exclude: Optional[str] = None):
        for pid, ws in self.connections.items():
            if pid != exclude:
                try:
                    await ws.send(json.dumps(message))
                except websockets.exceptions.ConnectionClosed:
                    pass

    def _validate_item_ownership(self, item_id: str, player_id: str) -> tuple[bool, str]:
        """Validate that an item exists and is owned by the specified player. 
        Must be called while holding the appropriate locks."""
        if item_id not in self.items:
            return False, f"Item {item_id} does not exist"
        item = self.items[item_id]
        if item.owner_id != player_id:
            return False, f"Item {item_id} is not owned by player {player_id}"
        if item_id not in self.players[player_id].inventory:
            return False, f"Item {item_id} not in player {player_id} inventory (inconsistency detected)"
        return True, "ok"

    async def handle_direct_transfer(self, from_player_id: str, to_player_id: str, item_id: str) -> dict:
        """Transfer a single item directly from one player to another with full locking."""
        if from_player_id not in self.players:
            return {"type": "error", "message": "Source player not found"}
        if to_player_id not in self.players:
            return {"type": "error", "message": "Target player not found"}
        if from_player_id == to_player_id:
            return {"type": "error", "message": "Cannot transfer to yourself"}

        # Acquire locks in consistent order (sorted by ID) to prevent deadlocks
        lock_order = sorted([from_player_id, to_player_id])
        lock1 = self._get_player_lock(lock_order[0])
        lock2 = self._get_player_lock(lock_order[1])
        item_lock = self._get_item_lock(item_id)

        async with lock1:
            async with lock2:
                async with item_lock:
                    # Validate ownership
                    valid, msg = self._validate_item_ownership(item_id, from_player_id)
                    if not valid:
                        return {"type": "error", "message": msg}

                    # Check neither player is in an active trade
                    if from_player_id in self.players_in_trade:
                        return {"type": "error", "message": "Source player is currently in a trade"}
                    if to_player_id in self.players_in_trade:
                        return {"type": "error", "message": "Target player is currently in a trade"}

                    # Perform the transfer atomically
                    item = self.items[item_id]
                    self.players[from_player_id].inventory.remove(item_id)
                    item.owner_id = to_player_id
                    self.players[to_player_id].inventory.append(item_id)

        result = {
            "type": "transfer_complete",
            "item_id": item_id,
            "from_player": from_player_id,
            "to_player": to_player_id,
            "item": self.items[item_id].to_dict(),
        }

        await self.send_to_player(to_player_id, {
            "type": "item_received",
            "item": self.items[item_id].to_dict(),
            "from_player": from_player_id,
        })

        return result

    async def handle_initiate_trade(self, initiator_id: str, receiver_id: str) -> dict:
        if initiator_id not in self.players:
            return {"type": "error", "message": "Initiator not found"}
        if receiver_id not in self.players:
            return {"type": "error", "message": "Receiver not found"}
        if initiator_id == receiver_id:
            return {"type": "error", "message": "Cannot trade with yourself"}
        if receiver_id not in self.connections:
            return {"type": "error", "message": "Receiver is not online"}

        async with self.trade_lock:
            if initiator_id in self.players_in_trade:
                return {"type": "error", "message": "You are already in a trade"}
            if receiver_id in self.players_in_trade:
                return {"type": "error", "message": "Target player is already in a trade"}

            trade_id = str(uuid.uuid4())
            trade = TradeOffer(
                trade_id=trade_id,
                initiator_id=initiator_id,
                receiver_id=receiver_id,
            )
            self.active_trades[trade_id] = trade
            self.players_in_trade.add(initiator_id)
            self.players_in_trade.add(receiver_id)

        await self.send_to_player(receiver_id, {
            "type": "trade_request",
            "trade_id": trade_id,
            "from_player": initiator_id,
            "from_name": self.players[initiator_id].name,
        })

        return {
            "type": "trade_initiated",
            "trade_id": trade_id,
            "with_player": receiver_id,
        }

    async def handle_add_to_trade(self, player_id: str, trade_id: str, item_ids: list, gold: int = 0) -> dict:
        if trade_id not in self.active_trades:
            return {"type": "error", "message": "Trade not found"}

        trade = self.active_trades[trade_id]

        if trade.state != TradeState.PENDING:
            return {"type": "error", "message": "Trade is not in pending state"}

        if player_id not in (trade.initiator_id, trade.receiver_id):
            return {"type": "error", "message": "You are not part of this trade"}

        is_initiator = player_id == trade.initiator_id
        other_player_id = trade.receiver_id if is_initiator else trade.initiator_id

        # Acquire player lock to validate inventory
        player_lock = self._get_player_lock(player_id)
        async with player_lock:
            player = self.players[player_id]

            if gold < 0:
                return {"type": "error", "message": "Gold amount cannot be negative"}
            if gold > player.gold:
                return {"type": "error", "message": "Insufficient gold"}

            # Validate all items
            for item_id in item_ids:
                valid, msg = self._validate_item_ownership(item_id, player_id)
                if not valid:
                    return {"type": "error", "message": msg}

            # Check for duplicate item IDs in the offer
            if len(item_ids) != len(set(item_ids)):
                return {"type": "error", "message": "Duplicate items in trade offer"}

            # Reset acceptance when trade contents change
            trade.initiator_accepted = False
            trade.receiver_accepted = False

            if is_initiator:
                trade.initiator_items = list(item_ids)
                trade.initiator_gold = gold
            else:
                trade.receiver_items = list(item_ids)
                trade.receiver_gold = gold

        await self.send_to_player(other_player_id, {
            "type": "trade_updated",
            "trade_id": trade_id,
            "trade": trade.to_dict(),
        })

        return {
            "type": "trade_updated",
            "trade_id": trade_id,
            "trade": trade.to_dict(),
        }

    async def handle_accept_trade(self, player_id: str, trade_id: str) -> dict:
        if trade_id not in self.active_trades:
            return {"type": "error", "message": "Trade not found"}

        trade = self.active_trades[trade_id]

        if trade.state not in (TradeState.PENDING,):
            return {"type": "error", "message": "Trade cannot be accepted in current state"}

        if player_id not in (trade.initiator_id, trade.receiver_id):
            return {"type": "error", "message": "You are not part of this trade"}

        is_initiator = player_id == trade.initiator_id
        other_player_id = trade.receiver_id if is_initiator else trade.initiator_id

        if is_initiator:
            trade.initiator_accepted = True
        else:
            trade.receiver_accepted = True

        # If both accepted, execute the trade
        if trade.initiator_accepted and trade.receiver_accepted:
            return await self._execute_trade(trade)

        await self.send_to_player(other_player_id, {
            "type": "trade_player_accepted",
            "trade_id": trade_id,
            "player_id": player_id,
        })

        return {
            "type": "trade_accepted",
            "trade_id": trade_id,
            "both_accepted": False,
        }

    async def _execute_trade(self, trade: TradeOffer) -> dict:
        """Execute a trade atomically with full validation and locking."""
        initiator_id = trade.initiator_id
        receiver_id = trade.receiver_id

        # Acquire locks in consistent order to prevent deadlocks
        lock_order = sorted([initiator_id, receiver_id])
        lock1 = self._get_player_lock(lock_order[0])
        lock2 = self._get_player_lock(lock_order[1])

        # Collect all item locks in sorted order
        all_item_ids = sorted(set(trade.initiator_items + trade.receiver_items))
        item_locks = [self._get_item_lock(iid) for iid in all_item_ids]

        async with lock1:
            async with lock2:
                # Acquire all item locks
                for il in item_locks:
                    await il.acquire()
                try:
                    # Re-validate everything under locks
                    initiator = self.players[initiator_id]
                    receiver = self.players[receiver_id]

                    # Validate initiator items
                    for item_id in trade.initiator_items:
                        valid, msg = self._validate_item_ownership(item_id, initiator_id)
                        if not valid:
                            trade.state = TradeState.CANCELLED
                            self._cleanup_trade(trade)
                            return {"type": "trade_failed", "message": f"Trade validation failed: {msg}"}

                    # Validate receiver items
                    for item_id in trade.receiver_items:
                        valid, msg = self._validate_item_ownership(item_id, receiver_id)
                        if not valid:
                            trade.state = TradeState.CANCELLED
                            self._cleanup_trade(trade)
                            return {"type": "trade_failed", "message": f"Trade validation failed: {msg}"}

                    # Validate gold
                    if trade.initiator_gold > initiator.gold:
                        trade.state = TradeState.CANCELLED
                        self._cleanup_trade(trade)
                        return {"type": "trade_failed", "message": "Initiator has insufficient gold"}

                    if trade.receiver_gold > receiver.gold:
                        trade.state = TradeState.CANCELLED
                        self._cleanup_trade(trade)
                        return {"type": "trade_failed", "message": "Receiver has insufficient gold"}

                    # Check for item overlap (same item offered by both - shouldn't happen but safety check)
                    initiator_set = set(trade.initiator_items)
                    receiver_set = set(trade.receiver_items)
                    if initiator_set & receiver_set:
                        trade.state = TradeState.CANCELLED
                        self._cleanup_trade(trade)
                        return {"type": "trade_failed", "message": "Item conflict detected"}

                    # === Execute the trade atomically ===

                    # Transfer initiator items to receiver
                    for item_id in trade.initiator_items:
                        initiator.inventory.remove(item_id)
                        self.items[item_id].owner_id = receiver_id
                        receiver.inventory.append(item_id)

                    # Transfer receiver items to initiator
                    for item_id in trade.receiver_items:
                        receiver.inventory.remove(item_id)
                        self.items[item_id].owner_id = initiator_id
                        initiator.inventory.append(item_id)

                    # Transfer gold
                    initiator.gold -= trade.initiator_gold
                    initiator.gold += trade.receiver_gold
                    receiver.gold -= trade.receiver_gold
                    receiver.gold += trade.initiator_gold

                    trade.state = TradeState.COMPLETED

                finally:
                    for il in item_locks:
                        il.release()

        # Cleanup trade tracking
        self._cleanup_trade(trade)

        trade_result = {
            "type": "trade_completed",
            "trade_id": trade.trade_id,
            "trade": trade.to_dict(),
        }

        # Notify both players
        await self.send_to_player(initiator_id, {
            "type": "trade_completed",
            "trade_id": trade.trade_id,
            "your_inventory": self.players[initiator_id].to_dict(),
        })
        await self.send_to_player(receiver_id, {
            "type": "trade_completed",
            "trade_id": trade.trade_id,
            "your_inventory": self.players[receiver_id].to_dict(),
        })

        return trade_result

    def _cleanup_trade(self, trade: TradeOffer):
        self.players_in_trade.discard(trade.initiator_id)
        self.players_in_trade.discard(trade.receiver_id)
        if trade.trade_id in self.active_trades:
            del self.active_trades[trade.trade_id]

    async def handle_cancel_trade(self, player_id: str, trade_id: str) -> dict:
        if trade_id not in self.active_trades:
            return {"type": "error", "message": "Trade not found"}

        trade = self.active_trades[trade_id]

        if player_id not in (trade.initiator_id, trade.receiver_id):
            return {"type": "error", "message": "You are not part of this trade"}

        trade.state = TradeState.CANCELLED
        other_player_id = trade.receiver_id if player_id == trade.initiator_id else trade.initiator_id

        self._cleanup_trade(trade)

        await self.send_to_player(other_player_id, {
            "type": "trade_cancelled",
            "trade_id": trade_id,
            "cancelled_by": player_id,
        })

        return {
            "type": "trade_cancelled",
            "trade_id": trade_id,
        }

    async def handle_drop_item(self, player_id: str, item_id: str) -> dict:
        """Remove an item from a player's inventory (destroy it)."""
        player_lock = self._get_player_lock(player_id)
        item_lock = self._get_item_lock(item_id)

        async with player_lock:
            async with item_lock:
                if player_id in self.players_in_trade:
                    return {"type": "error", "message": "Cannot drop items while in a trade"}

                valid, msg = self._validate_item_ownership(item_id, player_id)
                if not valid:
                    return {"type": "error", "message": msg}

                self.players[player_id].inventory.remove(item_id)
                self.items[item_id].owner_id = None
                # Actually remove the item from the game to prevent duplication
                del self.items[item_id]

        return {
            "type": "item_dropped",
            "item_id": item_id,
        }

    async def handle_get_inventory(self, player_id: str) -> dict:
        if player_id not in self.players:
            return {"type": "error", "message": "Player not found"}

        player = self.players[player_id]
        items = []
        for item_id in player.inventory:
            if item_id in self.items:
                items.append(self.items[item_id].to_dict())

        return {
            "type": "inventory",
            "player": player.to_dict(),
            "items": items,
        }

    async def handle_list_players(self, requesting_player_id: str) -> dict:
        online_players = []
        for pid in self.connections:
            if pid != requesting_player_id and pid in self.players:
                p = self.players[pid]
                online_players.append({"player_id": p.player_id, "name": p.name})

        return {
            "type": "player_list",
            "players": online_players,
        }

    async def handle_message(self, player_id: str, message: dict) -> dict:
        msg_type = message.get("type")

        if msg_type == "get_inventory":
            return await self.handle_get_inventory(player_id)

        elif msg_type == "list_players":
            return await self.handle_list_players(player_id)

        elif msg_type == "transfer_item":
            to_player = message.get("to_player_id")
            item_id = message.get("item_id")
            if not to_player or not item_id:
                return {"type": "error", "message": "Missing to_player_id or item_id"}
            return await self.handle_direct_transfer(player_id, to_player, item_id)

        elif msg_type == "initiate_trade":
            receiver_id = message.get("receiver_id")
            if not receiver_id:
                return {"type": "error", "message": "Missing receiver_id"}
            return await self.handle_initiate_trade(player_id, receiver_id)

        elif msg_type == "add_to_trade":
            trade_id = message.get("trade_id")
            item_ids = message.get("item_ids", [])
            gold = message.get("gold", 0)
            if not trade_id:
                return {"type": "error", "message": "Missing trade_id"}
            return await self.handle_add_to_trade(player_id, trade_id, item_ids, gold)

        elif msg_type == "accept_trade":
            trade_id = message.get("trade_id")
            if not trade_id:
                return {"type": "error", "message": "Missing trade_id"}
            return await self.handle_accept_trade(player_id, trade_id)

        elif msg_type == "cancel_trade":
            trade_id = message.get("trade_id")
            if not trade_id:
                return {"type": "error", "message": "Missing trade_id"}
            return await self.handle_cancel_trade(player_id, trade_id)

        elif msg_type == "drop_item":
            item_id = message.get("item_id")
            if not item_id:
                return {"type": "error", "message": "Missing item_id"}
            return await self.handle_drop_item(player_id, item_id)

        else:
            return {"type": "error", "message": f"Unknown message type: {msg_type}"}

    async def handle_connection(self, websocket: websockets.WebSocketServerProtocol):
        player = None
        try:
            # Wait for login message
            raw = await websocket.recv()
            login_msg = json.loads(raw)

            if login_msg.get("type") != "login":
                await websocket.send(json.dumps({"type": "error", "message": "First message must be login"}))
                return

            player_name = login_msg.get("name", "Unknown")
            player = self.create_player(player_name)
            self.connections[player.player_id] = websocket

            await websocket.send(json.dumps({
                "type": "login_success",
                "player": player.to_dict(),
                "items": [self.items[iid].to_dict() for iid in player.inventory],
            }))

            await self.broadcast({
                "type": "player_joined",
                "player_id": player.player_id,
                "name": player.name,
            }, exclude=player.player_id)

            print(f"Player {player.name} ({player.player_id}) connected")

            async for raw_message in websocket:
                try:
                    message = json.loads(raw_message)
                    response = await self.handle_message(player.player_id, message)
                    await websocket.send(json.dumps(response))
                except json.JSONDecodeError:
                    await websocket.send(json.dumps({"type": "error", "message": "Invalid JSON"}))
                except Exception as e:
                    print(f"Error handling message from {player.player_id}: {e}")
                    await websocket.send(json.dumps({"type": "error", "message": "Internal server error"}))

        except websockets.exceptions.ConnectionClosed:
            pass
        except Exception as e:
            print(f"Connection error: {e}")
        finally:
            if player:
                # Cancel any active trades
                trades_to_cancel = []
                for tid, trade in list(self.active_trades.items()):
                    if player.player_id in (trade.initiator_id, trade.receiver_id):
                        trades_to_cancel.append(tid)

                for tid in trades_to_cancel:
                    await self.handle_cancel_trade(player.player_id, tid)

                if player.player_id in self.connections:
                    del self.connections[player.player_id]

                await self.broadcast({
                    "type": "player_left",
                    "player_id": player.player_id,
                    "name": player.name,
                })

                print(f"Player {player.name} ({player.player_id}) disconnected")

    async def start(self, host: str = "localhost", port: int = 8765):
        print(f"Starting MMO Game Server on ws://{host}:{port}")
        print("Waiting for player connections...")

        async with websockets.serve(self.handle_connection, host, port):
            await asyncio.Future()  # Run forever


async def run_test_client(name: str, actions: list, results: dict):
    """Test client for automated testing."""
    import websockets

    uri = "ws://localhost:8765"
    async with websockets.connect(uri) as ws:
        # Login
        await ws.send(json.dumps({"type": "login", "name": name}))
        response = json.loads(await ws.recv())
        player_id = response["player"]["player_id"]
        results[name] = {"player_id": player_id, "login": response, "actions": []}
        print(f"  [{name}] Logged in as {player_id}")

        for action in actions:
            action_type = action.get("type")

            if action_type == "wait":
                await asyncio.sleep(action.get("duration", 0.5))
                continue

            if action_type == "wait_for_message":
                msg = json.loads(await ws.recv())
                results[name]["actions"].append({"received": msg})
                print(f"  [{name}] Received: {msg['type']}")
                if "save_as" in action:
                    results[name][action["save_as"]] = msg
                continue

            # Replace placeholders
            msg = dict(action)
            for key, val in msg.items():
                if isinstance(val, str) and val.startswith("$"):
                    ref_name, ref_key = val[1:].split(".", 1)
                    if ref_name in results:
                        if ref_key == "player_id":
                            msg[key] = results[ref_name]["player_id"]
                        elif ref_key in results[ref_name]:
                            ref_data = results[ref_name][ref_key]
                            if isinstance(ref_data, dict):
                                # Navigate nested keys
                                parts = ref_key.split(".")
                                val_resolved = results[ref_name]
                                for p in parts:
                                    val_resolved = val_resolved[p]
                                msg[key] = val_resolved
                if isinstance(val, list):
                    new_list = []
                    for v in val:
                        if isinstance(v, str) and v.startswith("$"):
                            ref_parts = v[1:].split(".")
                            ref_name_l = ref_parts[0]
                            if ref_name_l in results:
                                obj = results[ref_name_l]
                                for rp in ref_parts[1:]:
                                    if isinstance(obj, dict):
                                        obj = obj[rp]
                                    elif isinstance(obj, list):
                                        obj = obj[int(rp)]
                                new_list.append(obj)
                            else:
                                new_list.append(v)
                        else:
                            new_list.append(v)
                    msg[key] = new_list

            await ws.send(json.dumps(msg))
            response = json.loads(await ws.recv())
            results[name]["actions"].append({"sent": msg, "response": response})
            print(f"  [{name}] {action_type} -> {response['type']}")

            if "save_as" in action:
                results[name][action["save_as"]] = response


async def run_tests():
    """Run automated tests to demonstrate the system."""
    print("\n=== Running Automated Tests ===\n")
    await asyncio.sleep(1)  # Wait for server to start

    results = {}

    # Test 1: Basic login and inventory
    print("Test 1: Login and check inventory")
    await run_test_client("Alice", [
        {"type": "get_inventory"},
    ], results)

    # Test 2: Two players trade
    print("\nTest 2: Two-player trade")
    results.clear()

    async def alice_trade():
        await run_test_client("Alice", [
            {"type": "get_inventory", "save_as": "inv"},
            {"type": "wait", "duration": 1},
            {"type": "list_players"},
            {"type": "initiate_trade", "receiver_id": "$Bob.player_id", "save_as": "trade_init"},
            {"type": "wait", "duration": 0.5},
            # Alice adds her first item and 100 gold
            {"type": "add_to_trade",
             "trade_id": "$Alice.trade_init.trade_id",
             "item_ids": ["$Alice.inv.items.0.item_id"],
             "gold": 100},
            {"type": "wait", "duration": 0.5},
            {"type": "accept_trade", "trade_id": "$Alice.trade_init.trade_id"},
            {"type": "wait", "duration": 1},
            {"type": "wait_for_message", "save_as": "trade_result"},
            {"type": "get_inventory"},
        ], results)

    async def bob_trade():
        await run_test_client("Bob", [
            {"type": "get_inventory", "save_as": "inv"},
            {"type": "wait", "duration": 2},
            {"type": "wait_for_message", "save_as": "trade_req"},
            {"type": "wait_for_message"},  # trade_updated from Alice
            {"type": "add_to_trade",
             "trade_id": "$Bob.trade_req.trade_id",
             "item_ids": ["$Bob.inv.items.0.item_id"],
             "gold": 50},
            {"type": "wait", "duration": 0.5},
            {"type": "wait_for_message"},  # Alice accepted
            {"type": "accept_trade", "trade_id": "$Bob.trade_req.trade_id"},
            {"type": "get_inventory"},
        ], results)

    await asyncio.gather(alice_trade(), bob_trade())

    # Test 3: Attempt duplicate item transfer (should fail)
    print("\nTest 3: Duplicate prevention test")
    results.clear()

    async def charlie_dup_test():
        await run_test_client("Charlie", [
            {"type": "get_inventory", "save_as": "inv"},
            {"type": "wait", "duration": 1},
            # Try to transfer same item to two different players simultaneously
            {"type": "transfer_item",
             "to_player_id": "$Dave.player_id",
             "item_id": "$Charlie.inv.items.0.item_id"},
            {"type": "wait", "duration": 0.3},
            # Try again - should fail since item already transferred
            {"type": "transfer_item",
             "to_player_id": "$Eve.player_id",
             "item_id": "$Charlie.inv.items.0.item_id"},
        ], results)

    async def dave_dup_test():
        await run_test_client("Dave", [
            {"type": "get_inventory", "save_as": "inv"},
            {"type": "wait", "duration": 3},
            {"type": "get_inventory"},
        ], results)

    async def eve_dup_test():
        await run_test_client("Eve", [
            {"type": "get_inventory", "save_as": "inv"},
            {"type": "wait", "duration": 3},
            {"type": "get_inventory"},
        ], results)

    await asyncio.gather(charlie_dup_test(), dave_dup_test(), eve_dup_test())

    print("\n=== All Tests Complete ===")


async def main():
    server = GameServer()

    # Start server and tests concurrently
    server_task = asyncio.create_task(server.start("localhost", 8765))

    # Give server time to start, then run tests
    await asyncio.sleep(0.5)

    try:
        await asyncio.wait_for(run_tests(), timeout=30)
    except asyncio.TimeoutError:
        print("Tests timed out")
    except Exception as e:
        print(f"Test error: {e}")
        import traceback
        traceback.print_exc()

    print("\nServer continues running. Press Ctrl+C to stop.")
    await server_task


if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        print("\nServer shut down.")